import{_ as e,o as l,c as r,a4 as i}from"./chunks/framework.BhEBm8_q.js";const _=JSON.parse('{"title":"검색 사용하기","description":"","frontmatter":{},"headers":[],"relativePath":"07-search.md","filePath":"07-search.md"}'),o={name:"07-search.md"};function t(c,a,d,h,n,s){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="검색-사용하기" tabindex="-1">검색 사용하기 <a class="header-anchor" href="#검색-사용하기" aria-label="Permalink to “검색 사용하기”">​</a></h1><p><em>검색 결과와 스니펫</em></p><p>ebookflowy는 파일명 검색과 본문 검색을 구분해서 다룹니다. &quot;지금 읽는 문서 안&quot;과 &quot;보관함 전체&quot;를 따로 찾을 수 있습니다.</p><h2 id="현재-문서-안에서-검색" tabindex="-1">현재 문서 안에서 검색 <a class="header-anchor" href="#현재-문서-안에서-검색" aria-label="Permalink to “현재 문서 안에서 검색”">​</a></h2><p>리더 도구막대의 검색으로 지금 열려 있는 문서를 검색하고, 결과 위치로 바로 이동할 수 있습니다. 긴 PDF나 책에서 특정 단어를 찾을 때 유용합니다.</p><h2 id="보관함-본문-검색" tabindex="-1">보관함 본문 검색 <a class="header-anchor" href="#보관함-본문-검색" aria-label="Permalink to “보관함 본문 검색”">​</a></h2><p>하단 <code>검색</code> 탭에서는 색인된 문서의 본문 전체를 검색합니다.</p><ul><li>색인 대상: PDF, TXT, Markdown, EPUB, HWP/HWPX</li><li>CBZ/CB7은 텍스트가 없는 문서로 처리됩니다.</li><li>결과는 파일명, 파일 타입, 위치(페이지/오프셋), 스니펫(본문 일부), 매칭 수와 함께 표시됩니다.</li></ul><h2 id="한글-검색-정책" tabindex="-1">한글 검색 정책 <a class="header-anchor" href="#한글-검색-정책" aria-label="Permalink to “한글 검색 정책”">​</a></h2><p>한글은 검색어 길이에 따라 다른 방식이 쓰입니다.</p><ul><li>3글자 이상: 부분 검색(가운데 글자 매칭에 강함)</li><li>1~2글자: 보조 검색으로 함께 찾아 줌</li></ul><p>영문·숫자는 단어 단위로 검색되고, 파일명은 별도 색인으로 빠르게 찾습니다.</p><h2 id="필터와-검색-결과-큐" tabindex="-1">필터와 검색 결과 큐 <a class="header-anchor" href="#필터와-검색-결과-큐" aria-label="Permalink to “필터와 검색 결과 큐”">​</a></h2><p>검색 범위(scope)와 파일 타입으로 결과를 좁힐 수 있습니다. 결과 목록은 그대로 전환 큐가 되어, 한 문서를 연 뒤 두 손가락 스와이프로 다음·이전 결과 문서를 이어 볼 수 있습니다. 검색 → 비교 → 다음 문서로 이어지는 흐름이 끊기지 않습니다.</p><h2 id="색인과-실패-처리" tabindex="-1">색인과 실패 처리 <a class="header-anchor" href="#색인과-실패-처리" aria-label="Permalink to “색인과 실패 처리”">​</a></h2><p>검색을 하려면 문서가 색인되어 있어야 합니다.</p><ul><li>색인이 아직인 문서는 대기 상태로 표시됩니다.</li><li>색인에 실패한 문서는 <code>검색</code> 화면에서 다시 시도할 수 있습니다.</li><li>한 문서가 실패해도 다른 문서 검색에는 영향이 없습니다.</li></ul><blockquote><p>폴더를 통째로 색인하려면 <code>매직보관함</code>을 참고하세요.</p></blockquote>',18)])])}const m=e(o,[["render",t]]);export{_ as __pageData,m as default};
